import json
import re
from collections import Counter, defaultdict

# Load books data
books_key = 'var_functions.query_db:16'
books_file = locals()[books_key]
with open(books_file, 'r') as f:
    books_data = json.load(f)

# Function to extract year
def extract_year(book_record):
    details = book_record.get('details', '')
    subtitle = book_record.get('subtitle', '')
    patterns = [
        r'(?i)(?:January|February|March|April|May|June|July|August|September|October|November|December)\s+\d{1,2},\s+(\d{4})',
        r'published.*?\b(\d{4})\b',
        r'released.*?\b(\d{4})\b',
        r'\b(\d{4})\b'
    ]
    combined_text = details + ' ' + subtitle
    for pattern in patterns:
        matches = re.findall(pattern, combined_text)
        if matches:
            for year_str in matches:
                try:
                    year = int(year_str)
                    if 1900 <= year <= 2023:
                        return year
                except ValueError:
                    continue
    return None

# Create book_id to decade mapping
book_to_decade = {}
for book in books_data:
    year = extract_year(book)
    if year:
        decade = (year // 10) * 10
        book_to_decade[book['book_id']] = decade

# Load reviews data
reviews_key = 'var_functions.query_db:28'
reviews_file = locals()[reviews_key]
with open(reviews_file, 'r') as f:
    reviews_data = json.load(f)

# Group ratings by decade and count distinct books
decade_ratings = defaultdict(list)
decade_books = defaultdict(set)

for review in reviews_data:
    purchase_id = review.get('purchase_id', '')
    if not purchase_id:
        continue

    # Convert purchase_id to book_id
    book_id = purchase_id.replace('purchaseid_', 'bookid_')

    if book_id in book_to_decade:
        decade = book_to_decade[book_id]
        try:
            rating = float(review.get('rating', 0))
            if rating > 0:
                decade_ratings[decade].append(rating)
                decade_books[decade].add(book_id)
        except (ValueError, TypeError):
            pass

# Calculate statistics for decades with at least 10 distinct books
decade_stats = {}
for decade in decade_ratings:
    num_books = len(decade_books[decade])
    if num_books >= 10:
        avg_rating = sum(decade_ratings[decade]) / len(decade_ratings[decade])
        decade_stats[decade] = {
            'num_books': num_books,
            'num_reviews': len(decade_ratings[decade]),
            'avg_rating': round(avg_rating, 3)
        }

# Sort by average rating
decades_by_rating = sorted(decade_stats.items(), key=lambda x: x[1]['avg_rating'], reverse=True)

print("__RESULT__:")
print(json.dumps({
    'decade_statistics': decade_stats,
    'decades_sorted_by_rating': [(decade, stats['avg_rating']) for decade, stats in decades_by_rating],
    'top_decade': decades_by_rating[0] if decades_by_rating else None
}))

